**Here's a comprehensive set of pytest-style unit tests for the `memoize` decorator:**

```python
import pytest
from functools import wraps
from unittest.mock import Mock, call


def memoize(fn):
    cache = {}
    def wrapper(*args):
        if args not in cache:
            cache[args] = fn(*args)
        return cache[args]
    return wrapper


# ==================== Test Fixtures ====================

@pytest.fixture
def mock_fn():
    """Return a mock function that returns the first argument."""
    mock = Mock()
    mock.side_effect = lambda x: x
    return mock


@pytest.fixture
def mock_fn_with_side_effects():
    """Return a mock that increments a counter each time it's called."""
    counter = {'count': 0}

    def fn(x):
        counter['count'] += 1
        return x * 2

    mock = Mock(wraps=fn)
    mock.counter = counter
    return mock


# ==================== Happy Path Tests ====================

def test_memoize_returns_correct_value():
    @memoize
    def add(a, b):
        return a + b

    assert add(2, 3) == 5
    assert add(10, -5) == 5


def test_memoize_caches_results(mock_fn_with_side_effects):
    """Test that the wrapped function is only called once for the same arguments."""
    @memoize
    def double(x):
        return mock_fn_with_side_effects(x)

    # First call should execute the function
    assert double(5) == 10
    assert mock_fn_with_side_effects.counter['count'] == 1

    # Second call with same args should use cache
    assert double(5) == 10
    assert mock_fn_with_side_effects.counter['count'] == 1  # Still 1

    # Different argument should trigger function call
    assert double(7) == 14
    assert mock_fn_with_side_effects.counter['count'] == 2


def test_memoize_with_multiple_arguments():
    call_count = {'count': 0}

    @memoize
    def complex_func(a, b, c):
        call_count['count'] += 1
        return a * b + c

    assert complex_func(2, 3, 4) == 10
    assert complex_func(2, 3, 4) == 10
    assert call_count['count'] == 1

    assert complex_func(5, 1, 1) == 6
    assert call_count['count'] == 2


def test_memoize_preserves_function_name_and_docstring():
    """Test that the wrapper preserves metadata (using wraps is recommended but not used here)."""
    def original_function(x):
        """This is a test function."""
        return x * x

    wrapped = memoize(original_function)

    assert wrapped.__name__ == 'wrapper'  # Note: without @wraps, name is 'wrapper'
    assert wrapped(5) == 25


