    call_count = {'count': 0}

    @memoize
    def no_arg_func():
        call_count['count'] += 1
        return "hello"

    assert no_arg_func() == "hello"
    assert no_arg_func() == "hello"
    assert call_count['count'] == 1


def test_memoize_with_none_values():
    call_count = {'count': 0}

    @memoize
    def process(value):
        call_count['count'] += 1
        return value is None

    assert process(None) is True
    assert process(None) is True
    assert call_count['count'] == 1


def test_memoize_with_different_types_of_arguments():
    call_count = {'count': 0}

    @memoize
    def identity(x):
        call_count['count'] += 1
        return x

    # Test with different hashable types
    assert identity(42) == 42
    assert identity("hello") == "hello"
    assert identity(True) is True
    assert identity((1, 2, 3)) == (1, 2, 3)

    assert call_count['count'] == 4


